import React from 'react';
import { Menu, Row, Col } from 'antd';
import { Link } from 'react-router-dom'; // If you are using React Router

const MegaMenu = () => {
  return (
    <Menu mode="horizontal">
      <Menu.SubMenu title="Mega Menu" style={{ width: '800px' }}>
        <Menu.ItemGroup title="Column 1">
          <Row gutter={[16, 16]}>
            <Col span={6}>
              <Link to="/">Link 1</Link>
            </Col>
            <Col span={6}>
              <Link to="/">Link 2</Link>
            </Col>
            <Col span={6}>
              <Link to="/">Link 3</Link>
            </Col>
            <Col span={6}>
              <Link to="/">Link 4</Link>
            </Col>
          </Row>
        </Menu.ItemGroup>

        {/* Add other Menu.ItemGroup sections for columns 2 through 5 */}
      </Menu.SubMenu>
    </Menu>
  );
};

export default MegaMenu;
